    }
    return taskDir;
}

// Line 565: Another synchronized method
public synchronized void clean() {  // Acquires StateDirectory's lock
    // ...
}

// Line 609: Another synchronized method that calls lock() internally
public synchronized void cleanRemovedTasks(final long cleanupDelayMs) {
    cleanRemovedTasksCalledByCleanerThread(cleanupDelayMs);
}

// Line 617-641: Inside cleanRemovedTasksCalledByCleanerThread
// Which is called from line 611 while HOLDING the StateDirectory lock
private void cleanRemovedTasksCalledByCleanerThread(final long cleanupDelayMs) {
    for (final TaskDirectory taskDir : listAllTaskDirectories()) {
        // ...
