private final Lock tasksAndActionsLock = new ReentrantLock();
private final Condition tasksAndActionsCondition = tasksAndActionsLock.newCondition();

// Line 175-182: Lock acquired in clearInputQueue
private void clearInputQueue() {
    tasksAndActionsLock.lock();
    try {
        tasksAndActions.clear();
    } finally {
        tasksAndActionsLock.unlock();
    }
}

// Line 217-236: Lock acquired in performActionsOnTasks
private void performActionsOnTasks() {
    tasksAndActionsLock.lock();  // Line 218
    try {
        for (final TaskAndAction taskAndAction : tasksAndActions()) {
            final Action action = taskAndAction.action();
            switch (action) {
                case ADD:
                    addTask(taskAndAction.task());  // May call methods that acquire OTHER locks
                    break;
                case REMOVE:
                    removeTask(taskAndAction.taskId(), ...);  // May call methods that acquire OTHER locks
                    break;
            }
        }
    } finally {
        tasksAndActionsLock.unlock();
    }
}

// Line 337-342: Signal all while holding lock
if (setDeadline) {
    fetchDeadlineClientInstanceId = time.milliseconds() + timeout.toMillis();
    tasksAndActionsLock.lock();  // Line 337
    try {
        tasksAndActionsCondition.signalAll();  // Line 339
    } finally {
        tasksAndActionsLock.unlock();
    }
}
```

