                if (state != State.PENDING_SHUTDOWN) {
                    log.error("Global thread has died. The streams application or client will now close to ERROR.");
                    closeToError();
                }
            }
        }
    }

    private synchronized void registerStreamThread(final StreamThread streamThread) {
