129→                        progressed = true;
130→                    }
131→                }
132→
133→                if (taskExecutionMetadata.canPunctuateTask(currentTask)) {
134→                    if (currentTask.maybePunctuateStreamTime()) {
135→                        log.trace("punctuated stream time for task {} ", currentTask.id());
136→                        progressed = true;
137→                    }
