151→        private boolean processTask(final Task task, final long now, final Time time) {
152→            boolean processed = false;
153→            try {
154→                processed = task.process(now);
155→                if (processed) {
156→                    log.trace("Successfully processed task {}", task.id());
157→                    task.clearTaskTimeout();
