/**
 * Fray test that reproduces the deadlock between KafkaStreams.stateLock and
 * StreamStateListener's monitor.
 *
 * The deadlock pattern (before the fix):
 *   Thread A (addStreamThread, else branch): holds stateLock, calls
 *       streamThread.shutdown() → StreamThread.setState() → stateListener.onChange()
 *       which is synchronized on StreamStateListener → BLOCKED
 *   Thread B (StreamThread state change): holds StreamStateListener monitor
 *       (synchronized onChange), calls KafkaStreams.setState() →
 *       synchronized(stateLock) → BLOCKED
 *
 * After the fix, streamThread.shutdown() is called outside synchronized(stateLock),
 * breaking the circular dependency.
 */
public class DeadlockFrayTest {

    // Mirrors KafkaStreams.stateLock
    private static final Object stateLock = new Object();

    // Mirrors the StreamStateListener instance (whose methods are synchronized)
    private static final Object streamStateListenerLock = new Object();

    /**
     * Simulates the FIXED addStreamThread() else-branch:
     * 1. Check state under stateLock
     * 2. Release stateLock
     * 3. Call shutdown (which acquires streamStateListenerLock) outside stateLock
     */
    private static void addStreamThreadFixed() {
        final boolean shouldStart;
        synchronized (stateLock) {
            // Simulate: shouldStart = isRunningOrRebalancing();
            shouldStart = false; // force the else/shutdown branch
        }
        if (!shouldStart) {
            // streamThread.shutdown() → StreamThread.setState() → stateListener.onChange()
            synchronized (streamStateListenerLock) {
                // StreamStateListener.onChange does threadState bookkeeping
            }
        }
    }

    /**
     * Simulates a StreamThread state transition calling StreamStateListener.onChange()
     * which then calls KafkaStreams.setState() → synchronized(stateLock).
     */
    private static void streamThreadStateChange() {
        // StreamStateListener.onChange() is synchronized
        synchronized (streamStateListenerLock) {
            // Inside onChange, calls KafkaStreams.setState() which acquires stateLock
            synchronized (stateLock) {
                // KafkaStreams.setState: state = newState; stateLock.notifyAll();
            }
        }
    }

    public static void main(final String[] args) throws Exception {
        final Thread t1 = new Thread(DeadlockFrayTest::addStreamThreadFixed, "addStreamThread");
        final Thread t2 = new Thread(DeadlockFrayTest::streamThreadStateChange, "streamThreadStateChange");

        t1.start();
        t2.start();

        t1.join();
        t2.join();
    }
}

