447→    /**
448→     * Set the handler invoked when an internal {@link StreamsConfig#NUM_STREAM_THREADS_CONFIG stream thread}
449→     * throws an unexpected exception.
450→     * These might be exceptions indicating rare bugs in Kafka Streams, or they
451→     * might be exceptions thrown by your code, for example a NullPointerException thrown from your processor logic.
452→     * The handler will execute on the thread that produced the exception.
453→     * In order to get the thread that threw the exception, use {@code Thread.currentThread()}.
454→     * <p>
455→     * Note, this handler must be thread safe, since it will be shared among all threads, and invoked from any
456→     * thread that encounters such an exception.
457→     *
458→     * @param userStreamsUncaughtExceptionHandler the uncaught exception handler of type {@link StreamsUncaughtExceptionHandler} for all internal threads
459→     * @throws IllegalStateException if this {@code KafkaStreams} instance has already been started.
460→     * @throws NullPointerException if userStreamsUncaughtExceptionHandler is null.
461→     */
462→    public void setUncaughtExceptionHandler(final StreamsUncaughtExceptionHandler userStreamsUncaughtExceptionHandler) {
463→        synchronized (stateLock) {
464→            if (state.hasNotStarted()) {
465→                Objects.requireNonNull(userStreamsUncaughtExceptionHandler);
466→                streamsUncaughtExceptionHandler =
467→                    (exception, skipThreadReplacement) ->
468→                        handleStreamsUncaughtException(exception, userStreamsUncaughtExceptionHandler, skipThreadReplacement);
469→                processStreamThread(thread -> thread.setStreamsUncaughtExceptionHandler(streamsUncaughtExceptionHandler));
470→                if (globalStreamThread != null) {
471→                    globalStreamThread.setUncaughtExceptionHandler(
472→                        exception -> handleStreamsUncaughtException(exception, userStreamsUncaughtExceptionHandler, false)
473→                    );
474→                }
475→                processStreamThread(thread -> thread.setUncaughtExceptionHandler((t, e) -> { }
476→                ));
477→            } else {
478→                throw new IllegalStateException("Can only set UncaughtExceptionHandler before calling start(). " +
479→                    "Current state is: " + state);
480→            }
481→        }
482→    }
