611→    /**
612→     * Class that handles stream thread transitions
613→     */
614→    private final class StreamStateListener implements StreamThread.StateListener {
615→        private final Map<Long, StreamThread.State> threadState;
616→        private GlobalStreamThread.State globalThreadState;
617→
618→        StreamStateListener(final GlobalStreamThread.State globalThreadState) {
619→            this.threadState = new HashMap<>();
620→            this.globalThreadState = globalThreadState;
621→        }
622→
623→        /**
624→         * If all threads are up, including the global thread, set to RUNNING
625→         */
626→        private void maybeSetRunning() {
627→            // state can be transferred to RUNNING if
628→            // 1) all threads are either RUNNING or DEAD
629→            // 2) thread is pending-shutdown and there are still other threads running
630→            final boolean hasRunningThread = threadState.values().stream().anyMatch(s -> s == StreamThread.State.RUNNING);
631→            for (final StreamThread.State state : threadState.values()) {
632→                if (state == StreamThread.State.PENDING_SHUTDOWN && hasRunningThread) continue;
633→                if (state != StreamThread.State.RUNNING && state != StreamThread.State.DEAD) {
634→                    return;
635→                }
636→            }
637→
638→            // the global state thread is relevant only if it is started. There are cases
639→            // when we don't have a global state thread at all, e.g., when we don't have global KTables
640→            if (globalThreadState != null && globalThreadState != GlobalStreamThread.State.RUNNING) {
641→                return;
642→            }
643→
644→            setState(State.RUNNING);
645→        }
646→
647→
648→        @Override
649→        public synchronized void onChange(final Thread thread,
650→                                          final ThreadStateTransitionValidator abstractNewState,
651→                                          final ThreadStateTransitionValidator abstractOldState) {
652→            // StreamThreads first
653→            if (thread instanceof StreamThread) {
654→                final StreamThread.State newState = (StreamThread.State) abstractNewState;
655→                threadState.put(thread.getId(), newState);
656→
657→                if (newState == StreamThread.State.PARTITIONS_REVOKED || newState == StreamThread.State.PARTITIONS_ASSIGNED) {
658→                    setState(State.REBALANCING);
659→                } else if (newState == StreamThread.State.RUNNING) {
660→                    maybeSetRunning();
661→                }
662→            } else if (thread instanceof GlobalStreamThread) {
663→                // global stream thread has different invariants
664→                final GlobalStreamThread.State newState = (GlobalStreamThread.State) abstractNewState;
665→                globalThreadState = newState;
666→
667→                if (newState == GlobalStreamThread.State.RUNNING) {
668→                    maybeSetRunning();
669→                } else if (newState == GlobalStreamThread.State.DEAD) {
670→                    if (state != State.PENDING_SHUTDOWN) {
671→                        log.error("Global thread has died. The streams application or client will now close to ERROR.");
672→                        closeToError();
673→                    }
674→                }
675→            }
676→        }
677→
678→        private synchronized void registerStreamThread(final StreamThread streamThread) {
679→            threadState.put(streamThread.getId(), streamThread.state());
680→        }
681→    }
