101→    /**
102→     * @throws IllegalStateException if EOS is disabled
103→     */
104→    void initTransaction() {
105→        if (!eosEnabled()) {
106→            throw new IllegalStateException(formatException("Exactly-once is not enabled"));
107→        }
108→        if (!transactionInitialized) {
109→            // initialize transactions if eos is turned on, which will block if the previous transaction has not
110→            // completed yet; do not start the first transaction until the topology has been initialized later
111→            try {
112→                producer.initTransactions();
113→                transactionInitialized = true;
114→            } catch (final TimeoutException timeoutException) {
115→                log.warn(
116→                    "Timeout exception caught trying to initialize transactions. " +
117→                        "The broker is either slow or in bad state (like not having enough replicas) in " +
118→                        "responding to the request, or the connection to broker was interrupted sending " +
119→                        "the request or receiving the response. " +
120→                        "Will retry initializing the task in the next loop. " +
121→                        "Consider overwriting {} to a larger value to avoid timeout errors",
122→                    ProducerConfig.MAX_BLOCK_MS_CONFIG
123→                );
124→
125→                // re-throw to trigger `task.timeout.ms`
126→                throw timeoutException;
127→            } catch (final KafkaException exception) {
128→                throw new StreamsException(
129→                    formatException("Error encountered trying to initialize transactions"),
130→                    exception
131→                );
132→            }
133→        }
134→    }
