136→    public void resetProducer(final Producer<byte[], byte[]> producer) {
137→        if (!eosEnabled()) {
138→            throw new IllegalStateException("Expected EOS to be enabled, but processing mode is " + processingMode);
139→        }
140→
141→        oldProducerTotalBlockedTime += totalBlockedTime(this.producer);
142→        final long start = time.nanoseconds();
143→        close();
144→        final long closeTime = time.nanoseconds() - start;
145→        oldProducerTotalBlockedTime += closeTime;
146→
147→        this.producer = producer;
148→    }
