183→                    PosixFilePermission.OWNER_READ,
184→                    PosixFilePermission.OWNER_WRITE,
185→                    PosixFilePermission.OWNER_EXECUTE,
186→                    PosixFilePermission.GROUP_READ,
187→                    PosixFilePermission.GROUP_EXECUTE
188→            );
189→            if (config.getBoolean(StreamsConfig.ALLOW_OS_GROUP_WRITE_ACCESS_CONFIG)) {
190→                perms.add(PosixFilePermission.GROUP_WRITE);
191→            }
192→            try {
193→                Files.setPosixFilePermissions(path, perms);
194→            } catch (final IOException e) {
195→                log.error("Error changing permissions for the directory {} ", path, e);
196→            }
197→        } else {
198→            boolean set = file.setReadable(true, true);
199→            set &= file.setWritable(true, true);
200→            set &= file.setExecutable(true, true);
201→            if (!set) {
