 48→final class StateManagerUtil {
 49→    static final String CHECKPOINT_FILE_NAME = ".checkpoint";
 50→    static final long OFFSET_DELTA_THRESHOLD_FOR_CHECKPOINT = 10_000L;
 51→
 52→    private StateManagerUtil() {}
 53→
 54→    static RecordConverter converterForStore(final StateStore store) {
 55→        if (isHeadersAware(store)) {
 56→            return rawValueToHeadersValue();
 57→        } else if (isTimestamped(store) && !isVersioned(store)) {
 58→            // should not prepend timestamp when restoring records for versioned store, as
 59→            // timestamp is used separately during put() process for restore of versioned stores
 60→            return rawValueToTimestampedValue();
 61→        }
 62→        return identity();
 63→    }
 64→
 65→    static boolean checkpointNeeded(final boolean enforceCheckpoint,
 66→                                    final Map<TopicPartition, Long> oldOffsetSnapshot,
 67→                                    final Map<TopicPartition, Long> newOffsetSnapshot) {
 68→        // we should always have the old snapshot post completing the register state stores;
 69→        // if it is null it means the registration is not done and hence we should not overwrite the checkpoint
 70→        if (oldOffsetSnapshot == null) {
 71→            return false;
 72→        }
 73→
 74→        if (enforceCheckpoint)
 75→            return true;
 76→
 77→        // we can checkpoint if the difference between the current and the previous snapshot is large enough
 78→        long totalOffsetDelta = 0L;
 79→        for (final Map.Entry<TopicPartition, Long> entry : newOffsetSnapshot.entrySet()) {
 80→            totalOffsetDelta += entry.getValue() - oldOffsetSnapshot.getOrDefault(entry.getKey(), 0L);
 81→        }
 82→
 83→        // when enforcing checkpoint is required, we should overwrite the checkpoint if it is different from the old one;
 84→        // otherwise, we only overwrite the checkpoint if it is largely different from the old one
 85→        return totalOffsetDelta > OFFSET_DELTA_THRESHOLD_FOR_CHECKPOINT;
 86→    }
