 88→    /**
 89→     * @throws TaskCorruptedException if the state cannot be reused (with EOS) and needs to be reset
 90→     * @throws StreamsException If the store's changelog does not contain the partition
 91→     */
 92→    static void registerStateStores(final Logger log,
 93→                                    final String logPrefix,
 94→                                    final ProcessorTopology topology,
 95→                                    final ProcessorStateManager stateMgr,
 96→                                    final StateDirectory stateDirectory,
 97→                                    final InternalProcessorContext<?, ?> processorContext) {
 98→        if (topology.stateStores().isEmpty()) {
 99→            return;
100→        }
101→
102→        final TaskId id = stateMgr.taskId();
103→        if (!stateDirectory.lock(id)) {
104→            throw new LockException(String.format("%sFailed to lock the state directory for task %s", logPrefix, id));
105→        }
106→        log.debug("Acquired state directory lock");
107→
108→        final boolean storeDirsEmpty = stateDirectory.directoryForTaskIsEmpty(id);
109→
110→        stateMgr.registerStateStores(topology.stateStores(), processorContext);
111→        log.debug("Registered state stores");
112→
113→        // We should only load checkpoint AFTER the corresponding state directory lock has been acquired and
114→        // the state stores have been registered; we should not try to load at the state manager construction time.
115→        // See https://issues.apache.org/jira/browse/KAFKA-8574
116→        stateMgr.initializeStoreOffsetsFromCheckpoint(storeDirsEmpty);
117→        log.debug("Initialized state stores");
118→    }
