120→    /**
121→     * @throws ProcessorStateException if there is an error while closing the state manager
122→     */
123→    static void closeStateManager(final Logger log,
124→                                  final String logPrefix,
125→                                  final boolean closeClean,
126→                                  final boolean eosEnabled,
127→                                  final ProcessorStateManager stateMgr,
128→                                  final StateDirectory stateDirectory,
129→                                  final TaskType taskType) {
130→        // if EOS is enabled, wipe out the whole state store for unclean close since it is now invalid
131→        final boolean wipeStateStore = !closeClean && eosEnabled;
132→
133→        final TaskId id = stateMgr.taskId();
134→        log.trace("Closing state manager for {} task {}", taskType, id);
135→
136→        final AtomicReference<ProcessorStateException> firstException = new AtomicReference<>(null);
137→        try {
138→            if (stateDirectory.lock(id)) {
139→                try {
140→                    stateMgr.close();
141→                } catch (final ProcessorStateException e) {
142→                    firstException.compareAndSet(null, e);
143→                } finally {
144→                    try {
145→                        if (wipeStateStore) {
146→                            log.debug("Wiping state stores for {} task {}", taskType, id);
147→                            stateDirectory.removeTaskOffsets(id);
148→                            // we can just delete the whole dir of the task, including the state store images and the checkpoint files,
149→                            // and then we write an empty checkpoint file indicating that the previous close is graceful and we just
150→                            // need to re-bootstrap the restoration from the beginning
151→                            Utils.delete(stateMgr.baseDir());
152→                        }
153→                    } finally {
154→                        stateDirectory.unlock(id);
155→                    }
156→                }
157→            } else {
158→                log.warn("Unable to acquire lock while closing the state store for {} task {}", taskType, id);
159→            }
160→        } catch (final IOException e) {
161→            final ProcessorStateException exception = new ProcessorStateException(
162→                String.format("%sFatal error while trying to close the state manager for task %s", logPrefix, id), e
163→            );
164→            firstException.compareAndSet(null, exception);
165→        }
166→
167→        final ProcessorStateException exception = firstException.get();
168→        if (exception != null) {
169→            throw exception;
170→        }
171→    }
