169→    @Override
170→    public void unassignTask(final StreamTask task, final TaskExecutor executor) {
171→        executeWithTasksLocked(() -> {
172→            if (!taskExecutors.contains(executor)) {
173→                throw new IllegalArgumentException("The requested executor for unassign task is unrecognized");
174→            }
175→
176→            final TaskExecutor lockedExecutor = assignedTasks.get(task.id());
177→            if (lockedExecutor == null || lockedExecutor != executor) {
178→                throw new IllegalArgumentException("Task " + task.id() + " is not locked by the executor");
179→            }
180→
181→            assignedTasks.remove(task.id());
182→
183→            log.debug("Unassigned {} from executor {}", task.id(), executor.name());
184→            tasksCondition.signalAll();
185→        });
